"use strict";const DB={1:{ks:1,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","MTB-MLE"],data:{Science:{3:{5:{code:"S1FE-IIIi-j-5",text:"Use senses to locate and describe light sources in their immediate environment.",C:"Identify objects that produce light using visual senses.",P:"Sort objects into 'produces light' and 'does not produce light' categories.",A:"Describe how sunlight helps them perform daily activities.",pre:"Play an 'I Spy' sensory game: find objects that shine when window blinds open.",steps:[{n:1,t:"Paggamit ng Pandama",d:"Pupils walk around and list light-emitting objects seen (cellphones, windows, lights).",dp:["Clear goals","Scaffolding"]}],task:"Qualitative PACE checklist: can child point to light sources during observation?",rubric:"Skills observation checklist (Yes / Not Yet).",rem:"High-contrast pictorial sorting cards for one-on-one review.",enr:"Trace shadows of objects on paper outdoors.",home:"Draw 3 things at home that give light at night."}}},Mathematics:{1:{1:{code:"M1NS-Ia-1",text:"Count the number of objects in a given set up to 10.",C:"Count sets of objects up to 10 accurately.",P:"Write numerals 1–10 to match counted sets.",A:"Show patience and care when counting classroom objects.",pre:"Sing the counting song together and count fingers.",steps:[{n:1,t:"Counting with Blocks",d:"Use coloured blocks; teacher models counting 1–10, students follow.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Write the Number",d:"Students write the numeral matching their counted set on a mini whiteboard.",dp:["Active retrieval","Inclusion"]}],task:"Oral counting observation and number-writing activity in learner's book.",rubric:"PACE Form — Numeracy (Yes / Not Yet).",rem:"Number line poster for visual support during independent practice.",enr:"Count objects in a small bag and write the total.",home:"Count 5 items at home and draw them."}}},Filipino:{1:{1:{code:"F1OL-Ia-a-1",text:"Nakapagsasalita tungkol sa sarili nang may tiwala at kagalangan.",C:"Sabihin ang kanilang pangalan, edad, at paboritong bagay.",P:"Magsalita ng malinaw at may ekspresyon sa harap ng klase.",A:"Ipakita ang paggalang habang nakikinig sa iba.",pre:"Awit: 'Ang Aking Pangalan' — kantahin ng buong klase.",steps:[{n:1,t:"Pagpapakilala",d:"Bawat bata ay magsasabi ng kanilang pangalan at isang bagay na gusto nila.",dp:["Clear goals","Inclusion"]}],task:"Guro ay magmamasid at magtatala sa PACE Form.",rubric:"Yes / Not Yet — Oral Communication Checklist.",rem:"Picture cards bilang gabay sa pagpapakilala.",enr:"Iguhit ang sarili at ipaliwanag ang larawan.",home:"Ikwento sa magulang ang sariling pangalan at paboritong pagkain."}}},English:{1:{1:{code:"EN1OL-Ia-a-1",text:"Use oral language to communicate feelings and ideas in simple sentences.",C:"Identify and name feelings (happy, sad, angry, scared) using picture cues.",P:"Express a feeling using a complete simple sentence: 'I feel ____ because ____.'",A:"Listen respectfully when classmates share feelings.",pre:"Show feeling faces flashcards and ask pupils to mirror the expressions.",steps:[{n:1,t:"Feelings Vocabulary",d:"Teacher shows feeling cards; pupils say the feeling and act it out.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Sentence Practice",d:"In pairs, students take turns completing: 'I feel ___ today because ___.'",dp:["Social learning","Active retrieval"]}],task:"PACE observation: can the learner name and express 3 feelings?",rubric:"Yes / Not Yet — Oral Language Checklist.",rem:"Reduce to 2 target feelings; use sentence frame card.",enr:"Draw a feelings journal page showing 2 different moods.",home:"Tell a family member one thing that makes you happy and one thing that makes you sad."}}}}},2:{ks:1,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","MTB-MLE"],data:{Science:{3:{5:{code:"S2FE-IIIi-j-5",text:"Compare brightness of light sources and identify safety practices related to light.",C:"Compare light sources by brightness.",P:"Demonstrate safe behaviour near strong light sources.",A:"Appreciate sunlight as a free and natural resource.",pre:"Discussion: Which is brighter — candle, flashlight, or sun?",steps:[{n:1,t:"Brightness Card Ranking",d:"Students sort picture cards from dimmest to brightest and explain their order.",dp:["Clear goals","Active retrieval"]}],task:"PACE Form — Science Observation.",rubric:"Yes / Not Yet checklist.",rem:"Tactile brightness cards for guided review.",enr:"Draw a night scene using different light sources.",home:"Observe and list 3 light sources at home tonight."}}}}},3:{ks:1,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","MTB-MLE"],data:{Science:{3:{5:{code:"S3FE-IIIi-j-5.1",text:"Describe light sources and explore how light travels in a straight line through guided experiments.",C:"Classify light sources as natural (likas) or artificial (artipisyal).",P:"Demonstrate through guided experiments that light travels in a straight line.",A:"Value the practical role of light in daily safety (traffic lights, emergency flashlights).",pre:"Open-close eyes challenge: can you see colour in complete darkness? Pupils discuss.",steps:[{n:1,t:"Likas vs Artipisyal",d:"Teacher introduces natural (Sun, stars, fireflies) and artificial (bulbs, flashlights) sources via image-sort.",dp:["Clear goals","Scaffolding"]},{n:2,t:"Cardboard Hole Experiment",d:"Align 3 index cards with holes; shine flashlight through. Shift card 2 — light blocked. Light is straight!",dp:["Active retrieval","Social learning","Inclusion"]}],task:"Bilingual 5-item 'Likas o Artipisyal' formative check.",rubric:"KS1 Qualitative Rubric — Scientific Inquiry, Collaboration, Safety.",rem:"Match card blocks with 3D tactile objects during ARAL hour.",enr:"Shadow puppet challenge behind a light source.",home:"Find 5 household light sources at night and classify them."}}},Mathematics:{3:{5:{code:"M3NS-IIIi-j-50",text:"Perform operations on fractions with like and unlike denominators using models.",C:"Add and subtract fractions with like denominators using visual fraction bars.",P:"Model fraction addition with paper strips cut to equal parts.",A:"Show persistence when checking fraction answers with models.",pre:"Review: What is a fraction? Show pizza slices and label parts.",steps:[{n:1,t:"Fraction Bar Models",d:"Students cut equal strips to model 1/4 + 2/4 = 3/4 and similar problems.",dp:["Scaffolding","Active retrieval"]},{n:2,t:"Partner Check",d:"Pairs swap papers and verify each other's fraction models.",dp:["Social learning","Checks for understanding"]}],task:"5-item fraction addition worksheet with picture models.",rubric:"PACE Form — Mathematical Reasoning (Yes / Not Yet).",rem:"Colour-coded fraction wall for visual reference.",enr:"Create your own fraction story problem.",home:"Cut a piece of paper into equal parts and write a fraction to describe one part."}}}}},4:{ks:2,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","EPP/TLE"],data:{Science:{3:{5:{code:"S4FE-IIIi-j-5",text:"Demonstrate how light behaves through reflection, absorption, and transmission using simple experiments.",C:"Explain reflection, absorption, and transmission using experimental data.",P:"Conduct experiments using mirrors, coloured paper, and transparent materials.",A:"Appreciate the science behind everyday uses of light in technology and safety.",pre:"Recapitulate Grade 3 findings: light is straight. Now: what happens when it hits something?",steps:[{n:1,t:"Mirror Reflection Experiment",d:"Students use mirrors and flashlights; observe angle of incidence equals angle of reflection.",dp:["Active retrieval","Social Learning"]},{n:2,t:"OTT Classification",d:"Students sort classroom objects into Opaque, Translucent, Transparent categories.",dp:["Scaffolding","Clear goals"]}],task:"5-item formative quiz + lab observation checklist.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Concept-map review of OTT properties.",enr:"Design a simple periscope using two mirrors.",home:"List 3 transparent, 3 translucent, and 3 opaque objects at home."}}},Mathematics:{3:{5:{code:"M4NS-IIIi-j-70",text:"Multiply multi-digit numbers by 1- to 2-digit numbers using standard algorithm.",C:"Apply the standard multiplication algorithm to solve 3-digit by 2-digit problems.",P:"Set up and solve multiplication problems in vertical form with proper regrouping.",A:"Check work carefully and appreciate accuracy in calculation.",pre:"Warm-up: 12 × 4 — who can answer? How? Class shares strategies.",steps:[{n:1,t:"Step-by-Step Multiplication",d:"Teacher models 234 × 15 using step notation; students annotate steps in notebook.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Pair Practice",d:"Students solve 5 problems in pairs, checking after each answer.",dp:["Social Learning","Active retrieval"]}],task:"10-item written multiplication drill.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Multiplication table reference card for independent work.",enr:"Solve a real-world multi-step problem involving multiplication.",home:"Compute the total cost of 3 grocery items with your family."}}},Filipino:{3:{5:{code:"F4RC-IIIi-j-3",text:"Natutukoy ang mga pangunahing ideya at detalye mula sa tekstong babasahin.",C:"Tukuyin ang pangunahing ideya at tatlong detalye ng isang maikling teksto.",P:"Isulat ang pangunahing ideya at sumusuportang detalye sa graphic organizer.",A:"Magpakita ng malalim na pag-unawa sa nilalaman ng akda.",pre:"Ipakita ang larawan; itanong: Ano ang isinasalaysay ng larawan?",steps:[{n:1,t:"Pagbabasa ng Teksto",d:"Guro ay magbabasa ng maikling kwento; mga mag-aaral ay mag-iisip habang nakikinig.",dp:["Scaffolding","Active retrieval"]},{n:2,t:"Graphic Organizer",d:"Mag-aaral ay kukumpletuhin ang Main Idea + 3 Details na graphic organizer.",dp:["Clear goals","Social Learning"]}],task:"5-item comprehension check.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Simplified text with picture cues for struggling readers.",enr:"Sumulat ng sariling maikling kwento na may pangunahing ideya.",home:"Basahin ang isang pahayagan at hanapin ang pangunahing ideya ng isang balita."}}}}},5:{ks:2,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","EPP/TLE"],data:{Science:{3:{5:{code:"S5FE-IIIi-j-5",text:"Explain how light interacts with lenses and prisms to produce focus, dispersion, and colour separation.",C:"Explain how convex and concave lenses focus and diverge light.",P:"Observe colour dispersion using a prism and document results in a data table.",A:"Connect optics knowledge to real-world uses — eyeglasses, cameras, projectors.",pre:"Prism demonstration: white light disperses into ROYGBIV. What is happening?",steps:[{n:1,t:"Lens Types Comparison",d:"Students examine convex/concave lenses, draw ray diagrams, note convergence vs divergence.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Prism Rainbow Activity",d:"Groups place prisms near a window; observe and record colour sequence in data sheets.",dp:["Social Learning","Scaffolding"]}],task:"10-item formative identification quiz + ray diagram task.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Colour-labelled lens diagram reference for review.",enr:"Research how the human eye works like a lens system.",home:"Observe how eyeglasses or magnifiers bend light; write your observations."}}},Mathematics:{3:{5:{code:"M5NS-IIIi-j-90",text:"Solve problems involving division of decimals and mixed numbers.",C:"Divide decimals and mixed numbers using the standard algorithm.",P:"Set up and solve decimal division problems in vertical form.",A:"Verify answers and discuss reasonableness of results with peers.",pre:"Review: How is dividing whole numbers the same as dividing decimals? Students share ideas.",steps:[{n:1,t:"Decimal Division Algorithm",d:"Teacher models 12.6 ÷ 3 and 4.5 ÷ 1.5; students annotate process.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Real-World Problems",d:"Students solve 3 word problems involving money or measurement using decimal division.",dp:["Active retrieval","Social Learning"]}],task:"6-item written formative quiz.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Number line model for decimal placement review.",enr:"Create a shopping budget scenario that requires decimal division.",home:"Divide a family food bill among household members; show working."}}},English:{3:{5:{code:"EN5RC-IIIi-2",text:"Identify and analyse cause-and-effect relationships in informational texts.",C:"Distinguish cause from effect in informational paragraphs.",P:"Complete a cause-and-effect graphic organizer based on a given text.",A:"Appreciate how understanding cause-effect relationships helps in critical reading.",pre:"Quick visual: show domino effect picture. What caused the dominoes to fall?",steps:[{n:1,t:"Signal Words Hunt",d:"Students highlight cause (because, since, due to) and effect (therefore, so, as a result) signal words in a sample text.",dp:["Active retrieval","Clear goals"]},{n:2,t:"Graphic Organizer",d:"Pairs complete a cause-effect web based on a short news article extract.",dp:["Social Learning","Scaffolding"]}],task:"5-item formative comprehension exercise.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Sentence frame: 'The cause was ___ therefore the effect was ___.'",enr:"Write an original paragraph with one cause and two effects.",home:"Find a news headline and identify the cause and effect described."}}},"Araling Panlipunan":{3:{5:{code:"AP5PKB-IIIi-j-7",text:"Ipaliwanag ang papel ng mga likas na yaman sa pag-unlad ng ekonomiya ng Pilipinas.",C:"Tukuyin ang tatlong pangunahing likas na yaman ng Pilipinas at ang kanilang kaugnayan sa ekonomiya.",P:"Gumawa ng isang simpleng mapa na nagpapakita ng distribusyon ng likas na yaman sa iba't ibang rehiyon.",A:"Pagpapakita ng pagmamahal sa kalikasan at responsableng paggamit ng likas na yaman.",pre:"Ipakita ang mapa ng Pilipinas — saan matatagpuan ang mga pangunahing likas na yaman?",steps:[{n:1,t:"Likas na Yaman Bilang Kayamanan",d:"Grupo ay gagawa ng talaan ng likas na yaman (mineral, kagubatan, karagatan) sa kanilang lalawigan.",dp:["Clear goals","Social Learning"]},{n:2,t:"Resource Map Activity",d:"Mag-aaral ay maglalagay ng simbolo ng likas na yaman sa simpleng mapa ng Pilipinas.",dp:["Scaffolding","Active retrieval"]}],task:"5-item formative identification quiz.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Picture-labelled reference card ng likas na yaman.",enr:"Magsaliksik tungkol sa isang nanganganib na likas na yaman at magsulat ng rekomendasyon.",home:"Itanong sa magulang kung anu-anong likas na yaman ang ginagamit ng pamilya araw-araw."}}}}},6:{ks:2,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","EPP/TLE"],data:{Science:{3:{5:{code:"S6FE-IIIi-j-5",text:"Describe the electromagnetic spectrum and position visible light within the full range of EM radiation.",C:"Describe the EM spectrum from radio waves to gamma rays, in order of frequency.",P:"Arrange EM spectrum cards in order of increasing frequency and energy.",A:"Appreciate practical applications of EM radiation in medicine and communication.",pre:"Quick recall: visible light spectrum — name the colours. Where does this fit in a bigger picture?",steps:[{n:1,t:"Spectrum Card Sort",d:"Students sort labelled EM spectrum cards by wavelength and energy level and justify order.",dp:["Active retrieval","Scaffolding"]},{n:2,t:"Real-World Application Match",d:"Match each EM type to its application: radio→broadcast, X-ray→medical imaging, UV→sterilisation.",dp:["Clear goals","Social Learning"]}],task:"10-item EM spectrum identification and classification quiz.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Mnemonic: 'Radio Men In Vests Use X-ray Goggles' for recall.",enr:"Research how UV radiation affects skin cells; present findings.",home:"Identify 5 household devices that use EM radiation and classify each."}}}}},7:{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{Science:{3:{5:{code:"S7FE-IIIg-20",text:"Describe wave characteristics and differentiate mechanical from electromagnetic waves.",C:"Differentiate mechanical and electromagnetic waves using observable properties.",P:"Draw labelled wave diagrams showing amplitude, wavelength, frequency, and crest.",A:"Recognise how wave properties explain energy transfer in daily life.",pre:"Slinky demonstration: push-pull creates longitudinal; side-to-side creates transverse. Which is which?",steps:[{n:1,t:"Wave Properties Diagram",d:"Students label amplitude, wavelength, crest, trough, and compute frequency given period.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Mechanical vs EM Debate Cards",d:"Groups argue properties of assigned wave types; compare using structured comparison matrices.",dp:["Social Learning","Active retrieval"]}],task:"15-item formative test on wave properties + diagram performance task.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Wave property summary poster for guided review.",enr:"Research how seismographs use wave mechanics to detect earthquakes.",home:"Observe and describe 3 examples of wave motion in your home environment."}}},Mathematics:{3:{5:{code:"M7AL-IIIi-j-2",text:"Solve problems involving linear equations and inequalities in one variable.",C:"Apply properties of equality to isolate the variable in linear equations.",P:"Solve multi-step linear equations and check solutions by substitution.",A:"Value systematic thinking and verification in solving mathematical problems.",pre:"Puzzler: 'I am thinking of a number. When I double it and add 5, I get 17. What is it?'",steps:[{n:1,t:"Properties of Equality",d:"Teacher models solving 3x + 5 = 17 step-by-step; students annotate each property used.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Independent Equation Solving",d:"Students solve 6 linear equations and verify by substituting solutions back.",dp:["Active retrieval","Self-awareness and Metacognition"]}],task:"10-item written formative — solve and verify.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Equation balance model using scale diagram for visual learners.",enr:"Write and solve a word problem that requires a two-step linear equation.",home:"Write an equation for a real-life situation at home (e.g. sharing food equally) and solve it."}}},English:{3:{5:{code:"EN7RC-IIIi-j-8",text:"Distinguish between fact and opinion in informational and persuasive texts.",C:"Identify markers of fact (verifiable data) and opinion (belief, judgment) in written texts.",P:"Annotate a persuasive article marking facts (F) and opinions (O) for each claim.",A:"Develop critical reading habits by questioning the basis of claims in media.",pre:"Display a newspaper headline. Ask: Is this a fact or an opinion? How do you know?",steps:[{n:1,t:"Fact vs Opinion Markers",d:"Students study a sample editorial; highlight verifiable claims in blue, opinions in yellow.",dp:["Active retrieval","Clear goals"]},{n:2,t:"Pair Annotation Challenge",d:"Pairs annotate a new text and defend their F/O labels to another group.",dp:["Social Learning","Self-awareness and Metacognition"]}],task:"10-item formative F/O identification exercise.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Reference card: fact markers (statistics, dates, measurements) vs opinion markers (should, best, I believe).",enr:"Write a short editorial paragraph mixing facts and opinions; highlight both.",home:"Read a social media post and identify which claims are facts and which are opinions."}}}}},8:{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{Science:{3:{5:{code:"S8FE-IIIg-26",text:"Explain light propagation, reflection, and refraction through both wave and particle models.",C:"Differentiate wave-particle models and apply Snell's Law to calculate refraction angles.",P:"Construct ray diagrams showing refraction through convex lenses and prisms.",A:"Connect optics knowledge to corrective eyewear technology and student well-being.",pre:"Review wave behaviours with slinky demo; introduce the question: Is light a wave or a particle?",steps:[{n:1,t:"Wave vs Particle Model",d:"Students contrast Huygens' Wave Theory with Newton's Corpuscular Theory via comparison matrix.",dp:["Active retrieval","Self-awareness and Metacognition"]},{n:2,t:"Snell's Law Lab",d:"Students measure angles of incidence and refraction through glass slabs; compute n = sin θ₁/sin θ₂.",dp:["Scaffolding","Social Learning"]}],task:"10-item MCQ formative test + Snell's Law calculation items.",rubric:"WW 20%, PT 50%, ST 30%. Passing: raw ≥70% → transmuted grade ≥75%.",rem:"Peer-guided tutorial on refractive index calculations.",enr:"Research optical illusions in nature — mirages and rainbows; draft an explanation slide.",home:"Classify home light fixtures as reflective or diffusive; record in log journal."}}},Mathematics:{3:{5:{code:"M8GE-IIIi-j-5",text:"Prove geometric theorems involving triangles using deductive reasoning.",C:"Identify postulates and theorems needed to prove triangle congruence (SSS, SAS, ASA, AAS).",P:"Construct a two-column proof for a given pair of congruent triangles.",A:"Appreciate logical reasoning as a life skill beyond mathematics.",pre:"Display two triangles. Ask: How do we know these are exactly the same shape and size?",steps:[{n:1,t:"Congruence Postulate Review",d:"Students identify the minimum conditions (SSS, SAS, ASA, AAS) using triangle cut-outs.",dp:["Active retrieval","Scaffolding"]},{n:2,t:"Two-Column Proof Practice",d:"Students complete a guided two-column proof template, supplying justifications for each step.",dp:["Self-awareness and Metacognition","Clear goals"]}],task:"One proof construction task + 5 identification items.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Annotated sample proof for guided study.",enr:"Research the real-world application of triangle congruence in bridge engineering.",home:"Sketch a real object (table, roof, bridge) and identify congruent triangles within it."}}},Filipino:{3:{5:{code:"F8PL-IIIi-j-7",text:"Nasusuri ang mga pahayag para sa layunin, tono, at pagpapahalaga ng may-akda.",C:"Matukoy ang layunin, tono, at pananaw ng may-akda sa isang tekstong pampanitikan.",P:"Sumulat ng maikling pagsusuri na may ebidensya mula sa teksto.",A:"Mapaunlad ang kritikal na pag-iisip sa pamamagitan ng pagtatanong sa layunin ng teksto.",pre:"Ibahagi ang isang maikling tula. Itanong: Nakaramdam ba kayo ng damdamin habang ito ay binabasa?",steps:[{n:1,t:"Layunin at Tono",d:"Sama-samang tukuyin ang layunin ng teksto; makilala ang mga salitang nagpapahiwatig ng tono.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Pagsusuri ng Pananaw",d:"Mag-aaral ay sumusulat ng isang talata ng pagsusuri gamit ang IBT (Ideya-Batayan-Tono) na balangkas.",dp:["Scaffolding","Social Learning"]}],task:"Isang maikling pagsusuri na binibigyan ng marka ayon sa rubric.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Simpleng IBT graphic organizer para sa mga nangangailangan ng tulong.",enr:"Ihambing ang dalawang maikling tula ng magkaibang may-akda.",home:"Hanapin ang isang patalastas sa TV o social media at suriin ang layunin at tono nito."}}}}},9:{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{Science:{3:{5:{code:"S9FE-IIIg-30",text:"Apply mirror and lens formulas to explain real and virtual image formation.",C:"Apply the mirror formula 1/f = 1/do + 1/di to compute image distance and characterise images.",P:"Set up mirror/lens experiments and measure image characteristics; construct ray diagrams.",A:"Appreciate how image formation powers medical, media, and communication technology.",pre:"Concave mirror demo with candle: image appears inverted at a distance. Why?",steps:[{n:1,t:"Mirror Formula Application",d:"Students solve for image distance and classify images (real/virtual, upright/inverted, enlarged/reduced).",dp:["Checks for understanding","Active retrieval"]},{n:2,t:"Lens Optical Bench Lab",d:"Groups measure focal length of converging lens; compare to manufacturer specification.",dp:["Social Learning","Scaffolding"]}],task:"5-item calculation formative quiz + lab report PT.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Annotated formula reference cards.",enr:"Design a simple telescope or microscope using available lenses.",home:"Investigate how your phone camera uses lens principles; sketch the system."}}},Mathematics:{3:{5:{code:"M9AL-IIIi-j-4",text:"Solve systems of linear equations in two variables using substitution and elimination.",C:"Choose the appropriate method (substitution or elimination) to solve a system.",P:"Solve a system of two linear equations and verify by substitution.",A:"Recognise real-world situations that require simultaneous solutions.",pre:"Puzzle: 'Two numbers sum to 10 and differ by 2. What are they?' Students attempt different strategies.",steps:[{n:1,t:"Substitution Method",d:"Teacher models: if y = 2x, substitute into x + y = 9 to solve. Students replicate.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Elimination Method",d:"Students solve 3x + 2y = 12 and x - y = 1 by multiplying to eliminate one variable.",dp:["Active retrieval","Self-awareness and Metacognition"]}],task:"6-item mixed-method written formative.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Step-by-step substitution algorithm reference card.",enr:"Model a real-world scenario (e.g. ticket pricing) as a system and solve.",home:"Write a number puzzle for a family member that requires two equations to solve."}}}}},10:{ks:3,subjects:["Science","Mathematics","Filipino","English","Araling Panlipunan","MAPEH","TLE","Values Education"],data:{Science:{3:{5:{code:"S10FE-IIIh-50",text:"Explain interference and diffraction of light using the wave model.",C:"Apply Young's double-slit equations to calculate fringe spacing.",P:"Observe diffraction patterns and sketch bright and dark fringe positions.",A:"Connect diffraction principles to spectroscopy, holography, and anti-counterfeiting technology.",pre:"Laser through double-slit demo: pattern on screen. Students describe what they see.",steps:[{n:1,t:"Young's Double-Slit Analysis",d:"Students compute fringe spacing using y = λL/d and compare theoretical to observed values.",dp:["Self-awareness and Metacognition","Active retrieval"]},{n:2,t:"Pattern Sketching Lab",d:"Groups sketch and label bright and dark fringes from their own lab observation.",dp:["Social Learning","Clear goals"]}],task:"10-item written test on wave optics + calculation PT.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Annotated diagrams to revisit phase-difference concept.",enr:"Research how diffraction gratings work in spectroscopes; prepare a diagram.",home:"Observe iridescence in soap bubbles or CDs; explain the interference principle in writing."}}},Mathematics:{3:{5:{code:"M10AL-IIIi-j-7",text:"Determine the general term of sequences and solve problems involving arithmetic and geometric sequences.",C:"Identify the common difference or ratio and write the general term formula for a sequence.",P:"Use aₙ = a₁ + (n-1)d and aₙ = a₁·r^(n-1) to find specified terms.",A:"Recognise patterns in nature and design as manifestations of mathematical sequences.",pre:"Show: 2, 5, 8, 11… and 2, 6, 18, 54… Ask: What patterns do you see?",steps:[{n:1,t:"Arithmetic Sequence Formula",d:"Students identify d; use aₙ = a₁ + (n−1)d to find the 10th and 20th terms.",dp:["Scaffolding","Clear goals"]},{n:2,t:"Geometric Sequence Formula",d:"Students identify r; compute specified terms and write the general term formula.",dp:["Active retrieval","Self-awareness and Metacognition"]}],task:"10-item written formative — identify type, find terms.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Sequence formula reference card with worked examples.",enr:"Research the Fibonacci sequence in nature; identify 5 real-world examples.",home:"Write your own arithmetic or geometric sequence using objects at home (e.g. stacked coins, savings)."}}}}},11:{ks:4,subjects:["General Physics 1","General Mathematics","Oral Communication","Reading & Writing Skills","Understanding Culture, Society and Politics","Personal Development","Earth and Life Science","Media and Information Literacy","21st Century Literature","Contemporary Philippine Arts"],data:{"General Physics 1":{3:{5:{code:"STEM_GP12WP-IIIb-20",text:"Apply wave motion principles to explain propagation and characteristics of mechanical and electromagnetic waves.",C:"Calculate wave speed, frequency, and wavelength using v = fλ for real scenarios.",P:"Use a wave simulation or physical demonstration to measure wave parameters.",A:"Reflect on how wave physics underpins modern communication technology.",pre:"Review wave diagrams; students brainstorm: where do we encounter waves every day?",steps:[{n:1,t:"Wave Speed Calculations",d:"Students compute v = fλ for ocean waves, sound in air, and light in glass.",dp:["Checks for understanding","Active retrieval"]},{n:2,t:"Measurement Lab",d:"Using a slinky or wave tank, students measure amplitude, wavelength, and frequency directly.",dp:["Social Learning","Self-awareness and Metacognition"]}],task:"Quantitative 10-item problem set + lab report.",rubric:"WW 20%, PT 50%, ST 30% — Senior High School weights.",rem:"Wave equation drill with annotated solutions.",enr:"Research sonar and radar wave-property applications.",home:"Calculate the wavelength of an FM radio station given its broadcast frequency."}}},"General Mathematics":{3:{5:{code:"SHS_GM-IIIi-j-20",text:"Solve problems involving rational functions, equations, and inequalities.",C:"Determine the domain, range, and intercepts of rational functions.",P:"Solve rational equations by finding the LCD and verify solutions.",A:"Appreciate how rational functions model real-world scenarios such as rates, time, and work.",pre:"Review: what makes a fraction undefined? Apply to f(x) = 1/(x-2).",steps:[{n:1,t:"Rational Function Analysis",d:"Students find domain (exclude denominator zeros), x- and y-intercepts for 3 rational functions.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Solving Rational Equations",d:"Students solve (x+1)/(x-2) = 3 by multiplying both sides by LCD; check for extraneous solutions.",dp:["Scaffolding","Checks for understanding"]}],task:"8-item written formative — solve and verify.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"LCD identification algorithm reference card.",enr:"Graph a rational function and identify asymptotes using Desmos.",home:"Write a word problem that models a work-rate scenario using a rational equation."}}},"Oral Communication":{3:{5:{code:"OC11/12OP-IIIi-j-10",text:"Deliver a well-organised speech using clear pronunciation, appropriate pace, and effective non-verbal cues.",C:"Identify the components of effective oral delivery (pronunciation, rate, volume, eye contact, gestures).",P:"Deliver a 3-minute prepared speech applying all delivery components.",A:"Build confidence in public speaking by reflecting on strengths and areas for growth.",pre:"Show a short clip of an effective and an ineffective speaker. Students list differences.",steps:[{n:1,t:"Delivery Components Analysis",d:"Students use a rubric to evaluate the clip speakers; discuss: what made one more effective?",dp:["Active retrieval","Self-awareness and Metacognition"]},{n:2,t:"Prepared Speech Delivery",d:"Students deliver their 3-minute speeches; peers use a peer-evaluation form.",dp:["Social Learning","Checks for understanding"]}],task:"Speech delivery scored on Delivery Rubric (PT 50%).",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Provide sentence starters and outline template for struggling speakers.",enr:"Record speech and analyse delivery video for self-assessment.",home:"Practice the speech to a family member and note their feedback."}}},"Personal Development":{3:{5:{code:"PD11/12EsP-IIIi-j-3",text:"Reflect on personal strengths, limitations, and experiences that influence personal development.",C:"Identify personal strengths and limitations using validated self-assessment tools.",P:"Complete a Johari Window analysis and share insights with a trusted peer.",A:"Show openness to feedback as a foundation for lifelong self-improvement.",pre:"Journal entry prompt: 'What are 3 things you do well and 1 thing you would like to improve?'",steps:[{n:1,t:"Johari Window Activity",d:"Students fill in quadrants: known-known, blind spot, facade, unknown; discuss with a partner.",dp:["Self-awareness and Metacognition","Social Learning"]},{n:2,t:"Strength-Limitation Reflection",d:"Students write a structured reflection: strength → evidence → plan for a limitation.",dp:["Clear goals","Checks for understanding"]}],task:"Written reflection rubric-scored + Johari Window PT.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Pre-filled Johari Window template for guided completion.",enr:"Research a historical figure; analyse their Johari Window based on biographical evidence.",home:"Interview a trusted family member about your blind spot; write a response journal entry."}}}}},12:{ks:4,subjects:["General Physics 2","Practical Research 2","Oral Communication","Contemporary Philippine Arts","21st Century Literature","Physical Education and Health","Entrepreneurship","Earth Science"],data:{"General Physics 2":{3:{5:{code:"SPH12-IIIh-55",text:"Explain optical phenomena through wave-particle and photon theories and relate photon energy to EM frequencies.",C:"Calculate photon energy using Planck's equation E = hf; explain the Photoelectric Effect.",P:"Derive kinetic energy of photoelectrons given light frequency and work function of metals.",A:"Appreciate how quantum physics principles enable solar panel technology and clean energy.",pre:"Retrieve classical wave concepts; introduce ultraviolet catastrophe as trigger for quantum physics.",steps:[{n:1,t:"Photoelectric Effect — Einstein's Theory",d:"Derive E = hf; explain work function; solve for Ek = hf - φ using quantitative problem sets.",dp:["Checks for understanding","Self-awareness and Metacognition"]},{n:2,t:"Stopping Potential Calculations",d:"Students calculate stopping potential for various photoelectric targets and compare theoretical values.",dp:["Active retrieval","Scaffolding"]}],task:"8-item calculation-based formative on photon energy and stopping potentials.",rubric:"WW 20%, PT 50%, ST 30% — Senior High School weights.",rem:"Computational practice loop with annotated solution keys.",enr:"Present implications of Time Dilation on optical satellite communications.",home:"Draw a schematic of a home solar inverter converting light photon input to AC electricity."}}},"Practical Research 2":{3:{5:{code:"PR211-IIIi-j-15",text:"Interpret quantitative data using descriptive and inferential statistics and present findings clearly.",C:"Interpret mean, median, mode, standard deviation, and correlation coefficients from research data.",P:"Use statistical software or spreadsheet to compute and visualise descriptive statistics.",A:"Maintain academic integrity by accurately representing data without manipulation.",pre:"Show a data set; ask: What story does this data tell? What do these numbers mean?",steps:[{n:1,t:"Descriptive Statistics Review",d:"Students compute measures of central tendency and variability for a provided data set.",dp:["Active retrieval","Checks for understanding"]},{n:2,t:"Data Visualisation",d:"Students create an appropriate chart (bar, histogram, scatter) for their data in a spreadsheet.",dp:["Self-awareness and Metacognition","Clear goals"]}],task:"Data interpretation report — PT 50%.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Statistics formula reference sheet + calculator tutorial.",enr:"Run a Pearson correlation analysis on two research variables and interpret r.",home:"Identify the type of chart used in a news article and evaluate whether it accurately represents the data."}}},Entrepreneurship:{3:{5:{code:"ENT12-IIIi-j-8",text:"Develop a detailed business plan including marketing, operations, and financial projections.",C:"Identify the four components of a business plan (executive summary, marketing, operations, financials).",P:"Draft the marketing and operations sections for a student enterprise concept.",A:"Develop entrepreneurial confidence by connecting classroom learning to real business scenarios.",pre:"Mini pitch: 'You have P500 and 1 week. What business would you start?' Students share ideas.",steps:[{n:1,t:"Business Plan Structure",d:"Teacher presents a sample business plan; students identify each section and its purpose.",dp:["Clear goals","Active retrieval"]},{n:2,t:"Marketing & Operations Draft",d:"Small groups draft the marketing mix (4Ps) and an operations timeline for their enterprise idea.",dp:["Social Learning","Self-awareness and Metacognition"]}],task:"Business plan section draft — scored using Entrepreneurship PT rubric.",rubric:"WW 20%, PT 50%, ST 30%.",rem:"Guided business plan template with sentence starters per section.",enr:"Conduct a 5-person market survey and integrate data into the marketing section.",home:"Interview a local entrepreneur about their planning process; incorporate insights into the draft."}}}}}};function ksOf(e){const a=parseInt(e);return a<=3?1:a<=6?2:a<=10?3:4}function ksLabel(e){return["","Key Stage 1 · Grades 1–3","Key Stage 2 · Grades 4–6","Key Stage 3 · Grades 7–10","Key Stage 4 · Grades 11–12"][e]}let quill,_saveT;